// Extraer parcelas del FeatureCollection GML
const items = $input.all();
const leads = [];

for (const item of items) {
  const data = item.json;

  // El XML parseado expone la estructura GML anidada
  // Navegamos a los miembros del FeatureCollection
  let members = [];
  try {
    const fc = data.FeatureCollection;
    const rawMembers = fc.member || [];
    members = Array.isArray(rawMembers) ? rawMembers : [rawMembers];
  } catch (e) {
    continue;
  }

  for (const member of members) {
    try {
      const parcel = member['cp:CadastralParcel'];
      if (!parcel) continue;

      const refCatastral = parcel['cp:nationalCadastralReference']?.[0] || '';
      const area         = parcel['cp:areaValue']?.[0]?._ || parcel['cp:areaValue']?.[0] || '';
      const refPoint     = parcel['cp:referencePoint']?.[0];
      const posRaw       = refPoint?.['gml:Point']?.[0]?.['gml:pos']?.[0] || '';
      const [lat, lng]   = posRaw.trim().split(' ').map(Number);
      const label        = parcel['cp:label']?.[0] || '';

      if (!refCatastral) continue;

      leads.push({
        json: {
          source:              'catastro_inspire',
          nationalRef:         refCatastral,
          label,
          areaSqm:             parseFloat(area),
          lat,
          lng,
          // Campos requeridos por /api/radar/inbound
          user_id:             '06523398-43a6-42a8-896b-3307f14d7fda',
          name:                `Parcela ${refCatastral}`,
          description:         `Parcela catastral. Área: ${area} m². Ref: ${refCatastral}`,
          location:            `${lat},${lng}`,
          raw_source:          'catastro_inspire_wfs',
          score:               0.6
        }
      });
    } catch (e) {
      // Parcela malformada, skip
      continue;
    }
  }
}

if (leads.length === 0) {
  throw new Error('No se extrajeron parcelas del XML. Revisar estructura GML.');
}

return leads;

// Log de error para debugging
const item = $input.first().json;
console.error('Error al enviar lead a /inbound:', JSON.stringify(item));
return [{ json: { error: true, response: item } }];

// Éxito — lead registrado
const item = $input.first().json;
return [{ json: { ok: true, lead: item } }];
